  1	import * as React from 'react';
  2	import { ButtonBar } from '@odf/shared/generic/ButtonBar';
  3	import { IamCommands } from '@odf/shared/iam';
  4	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
  5	import { useModal } from '@openshift-console/dynamic-plugin-sdk';
  6	import { ModalComponent } from '@openshift-console/dynamic-plugin-sdk/lib/app/modal-support/ModalProvider';
  7	import {
  8	  Modal,
  9	  Button,
 10	  ModalVariant,
 11	  ButtonVariant,
 12	  FormGroup,
 13	  TextInput,
 14	  Text,
 15	  FormHelperText,
 16	  HelperText,
 17	  HelperTextItem,
 18	  ValidatedOptions,
 19	  ActionGroup,
 20	} from '@patternfly/react-core';
 21	import { AccessKeySecretKeyDisplayModal } from './AccessKeySecretKeyDisplayModal';
 22	
 23	type GenerateAnotherAccessKeyModalProps = ModalComponent<{
 24	  isOpen: boolean;
 25	  userName?: string;
 26	  refreshTokens?: () => void;
 27	  iamClient?: IamCommands;
 28	}>;
 29	
 30	const MAX_DESCRIPTION_LENGTH = 256;
 31	
 32	const validateDescription = (description: string): ValidatedOptions => {
 33	  if (!description) {
 34	    return ValidatedOptions.default;
 35	  }
 36	  if (description.length > MAX_DESCRIPTION_LENGTH) {
 37	    return ValidatedOptions.error;
 38	  }
 39	  return ValidatedOptions.default;
 40	};
 41	
 42	export const GenerateAnotherAccessKeyModal: GenerateAnotherAccessKeyModalProps =
 43	  ({ isOpen, closeModal, userName, refreshTokens, iamClient }) => {
 44	    const { t } = useCustomTranslation();
 45	    const MODAL_TITLE = t('Generate another access key');
 46	    const [description, setDescription] = React.useState('');
 47	    const [inProgress, setInProgress] = React.useState(false);
 48	    const [error, setError] = React.useState<Error>();
 49	    const descriptionValidationState = React.useMemo(
 50	      () => validateDescription(description),
 51	      [description]
 52	    );
 53	    const launchModal = useModal();
 54	
 55	    const onGenerate = React.useCallback(async () => {
 56	      if (descriptionValidationState === ValidatedOptions.error) {
 57	        return;
 58	      }
 59	      setInProgress(true);
 60	      try {
 61	        const response = await iamClient.createAccessKey({
 62	          UserName: userName,
 63	        });
 64	
 65	        // Save description as user tag (Key = AccessKeyId, Value = description)
 66	        if (response.AccessKey && description.trim()) {
 67	          await iamClient.tagUser({
 68	            UserName: userName,
 69	            Tags: [
 70	              {
 71	                Key: response.AccessKey.AccessKeyId,
 72	                Value: description.trim(),
 73	              },
 74	            ],
 75	          });
 76	        }
 77	
 78	        closeModal();
 79	        if (response.AccessKey) {
 80	          launchModal(AccessKeySecretKeyDisplayModal, {
 81	            isOpen: true,
 82	            extraProps: {
 83	              AccessKeyId: response.AccessKey.AccessKeyId,
 84	              SecretKey: response.AccessKey.SecretAccessKey,
 85	              title: t('Access key generated'),
 86	              buttonText: t('Done'),
 87	            },
 88	          });
 89	        }
 90	        setInProgress(false);
 91	        refreshTokens?.();
 92	      } catch (err) {
 93	        setInProgress(false);
 94	        setError(err);
 95	      }
 96	    }, [
 97	      closeModal,
 98	      description,
 99	      descriptionValidationState,
100	      iamClient,
101	      launchModal,
102	      refreshTokens,
103	      t,
104	      userName,
105	    ]);
106	
107	    return (
108	      <Modal
109	        isOpen={isOpen}
110	        onClose={closeModal}
111	        variant={ModalVariant.medium}
112	        title={MODAL_TITLE}
113	        actions={[
114	          <ButtonBar
115	            key="actions"
116	            inProgress={inProgress}
117	            errorMessage={error?.message}
118	          >
119	            <ActionGroup>
120	              <Button
121	                variant={ButtonVariant.primary}
122	                onClick={onGenerate}
123	                isDisabled={
124	                  inProgress ||
125	                  descriptionValidationState === ValidatedOptions.error
126	                }
127	              >
128	                {t('Generate')}
129	              </Button>
130	              <Button
131	                variant={ButtonVariant.link}
132	                onClick={closeModal}
133	                isDisabled={inProgress}
134	              >
135	                {t('Cancel')}
136	              </Button>
137	            </ActionGroup>
138	          </ButtonBar>,
139	        ]}
140	      >
141	        <FormGroup label={t('Username')} fieldId="username-input">
142	          <Text id="username-input">{userName}</Text>
143	        </FormGroup>
144	        <FormGroup
145	          label={t('Description tag')}
146	          fieldId="description-input"
147	          className="pf-v6-u-mt-md"
148	        >
149	          <TextInput
150	            id="description-input"
151	            type="text"
152	            value={description}
153	            onChange={(_event, value) => setDescription(value)}
154	            placeholder={t('Enter description')}
155	            aria-label={t('Description')}
156	            isDisabled={inProgress}
157	            validated={descriptionValidationState}
158	          />
159	          {descriptionValidationState === ValidatedOptions.error && (
160	            <FormHelperText>
161	              <HelperText>
162	                <HelperTextItem variant={ValidatedOptions.error}>
163	                  {t('No more than {{maxLength}} characters', {
164	                    maxLength: MAX_DESCRIPTION_LENGTH,
165	                  })}
166	                </HelperTextItem>
167	              </HelperText>
168	            </FormHelperText>
169	          )}
170	          {descriptionValidationState !== ValidatedOptions.error && (
171	            <FormHelperText>
172	              <HelperText>
173	                <HelperTextItem>
174	                  {t(
175	                    'Maximum 256 characters. Use a combination of letters, numbers, spaces and special characters.'
176	                  )}
177	                </HelperTextItem>
178	              </HelperText>
179	            </FormHelperText>
180	          )}
181	        </FormGroup>
182	      </Modal>
183	    );
184	  };

